const input = $input.first().json.body || $input.first().json;

const systemPrompt = `You are EduExpress International's senior content strategist. You write high-converting social media posts for Bangladesh students interested in studying abroad.

BRAND RULES:
- NEVER use: "guaranteed visa", "100% success", "free education", "no cost", "best consultancy", "No.1"
- Always use real, verifiable numbers (stipend range: ৳10,000-60,000/month)
- 50% Bangla + 50% English per post (mix naturally, technical terms stay English)
- Tone: ${input.tone || 'expert_consultant'}
- Include: facts, social proof, transparent costs, clear CTA
- Hook must be punchy (under 15 words)
- Body: 3-5 short paragraphs max
- Hashtags: 3-5 relevant tags

OUTPUT FORMAT (JSON):
{
  "hook": "...",
  "body": "...",
  "hashtags": "...",
  "cta": "...",
  "brief": "design brief for designer..."
}`;

const userPrompt = `Write a ${input.format || 'Carousel'} post for ${input.page === 'china' ? 'China' : 'Bangladesh'} page.

PILLAR: ${input.pillar}
TOPIC: ${input.topic || 'Study abroad opportunity'}
LANGUAGE: ${input.language}
${input.selectedUniversity ? `UNIVERSITY: ${input.selectedUniversity.name} — ${input.selectedUniversity.programs} (${input.selectedUniversity.city})` : ''}
${input.selectedScholarship ? `SCHOLARSHIP: ${input.selectedScholarship.name} — ${input.selectedScholarship.coverage}` : ''}
${input.researchIntel ? `RESEARCH INTEL: ${input.researchIntel.topic} — ${input.researchIntel.insight_summary}` : ''}

Write the post now.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    model: 'gemini-1.5-pro-latest',
    temperature: 0.7,
    maxOutputTokens: 1024,
    input: input
  }
}];

const { GoogleGenerativeAI } = require('@google/generative-ai');
const genAI = new GoogleGenerativeAI('AIzaSyBVNHLJH3BKL0dX1P33jG9b4m0K8Y2v0');
const model = genAI.getGenerativeModel({ model: 'gemini-1.5-pro-latest' });

const input = $input.first().json;
const result = await model.generateContent({
  contents: [
    { role: 'user', parts: [{ text: input.systemPrompt + '\n\n' + input.userPrompt }] }
  ],
  generationConfig: {
    temperature: 0.7,
    maxOutputTokens: 1024
  }
});

const text = result.response.text();
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  // Fallback: extract sections manually
  const hook = text.match(/hook[:\s]*"?([^"
]+)/i)?.[1] || text.split('\n')[0];
  const body = text.match(/body[:\s]*"?([^"]+)/is)?.[1] || text;
  const hashtags = text.match(/hashtags[:\s]*"?([^"
]+)/i)?.[1] || '#StudyAbroad';
  const cta = text.match(/cta[:\s]*"?([^"
]+)/i)?.[1] || 'DM us for details';
  parsed = { hook, body, hashtags, cta, brief: 'Auto-generated' };
}

return [{ json: { success: true, ...parsed, raw: text } }];
